def _format_float(value):
    """Format a floating number to make sure it gets the decimal point."""
    # Try using the string representation first, as it is often more compact
    value_str = str(value)

    # If the string representation is too long or doesn't have a decimal point,
    # use the explicit format with 16 significant digits
    if len(value_str) > 20 or ("." not in value_str and "e" not in value_str.lower()):
        value_str = f"{value:.16G}"
        if "." not in value_str and "E" not in value_str:
            value_str += ".0"

    # Normalize lowercase 'e' to uppercase 'E' for FITS compatibility
    if "e" in value_str:
        value_str = value_str.replace("e", "E")

    if "E" in value_str:
        # On some Windows builds of Python (and possibly other platforms?) the
        # exponent is zero-padded out to, it seems, three digits.  Normalize
        # the format to pad only to two digits.
        significand, exponent = value_str.split("E")
        if exponent[0] in ("+", "-"):
            sign = exponent[0]
            exponent = exponent[1:]
        else:
            sign = ""
        value_str = f"{significand}E{sign}{int(exponent):02d}"

    # Limit the value string to at most 20 characters.
    str_len = len(value_str)

    if str_len > 20:
        idx = value_str.find("E")

        if idx < 0:
            value_str = value_str[:20]
        else:
            value_str = value_str[: 20 - (str_len - idx)] + value_str[idx:]

    return value_str


def _pad(input):
    """Pad blank space to the input string to be multiple of 80."""
    _len = len(input)
    if _len == Card.length:
        return input
    elif _len > Card.length:
        strlen = _len % Card.length
        if strlen == 0:
            return input
        else:
            return input + " " * (Card.length - strlen)

    # minimum length is 80
    else:
        strlen = _len % Card.length
        return input + " " * (Card.length - strlen)

def test_floating_point_value_card(self):
    """Test Card constructor with floating point value"""

    c = fits.Card("floatnum", -467374636747637647347374734737437.0)

    if str(c) != _pad("FLOATNUM= -4.6737463674763E+32") and str(c) != _pad(
        "FLOATNUM= -4.6737463674763E+032"
    ):
        assert str(c) == _pad("FLOATNUM= -4.6737463674763E+32")

